module shift_register(
    input  clk,
    input  load,
    input  [3:0] data_in,
    output [3:0] data_out
);

reg [3:0] obf_register;

always @(posedge clk) begin
    if (load) begin
        obf_register <= data_in;
    end else begin
        obf_register <= {1'b0, obf_register[3:1]};
    end
end

assign data_out = obf_register;

endmodule
